import{c as t,Q as s,j as n,m as l}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"DevOps / SRE 系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"devopsLearning/00-写作计划.md","filePath":"devopsLearning/00-写作计划.md","lastUpdated":1778496697000}'),e={name:"devopsLearning/00-写作计划.md"};function i(o,a,r,p,d,u){return s(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="devops-sre-系列写作计划" tabindex="-1">DevOps / SRE 系列写作计划 <a class="header-anchor" href="#devops-sre-系列写作计划" aria-label="Permalink to &quot;DevOps / SRE 系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第三类「纵深主题」第八项(H),⭐⭐⭐⭐。 backendLearning 用 4 篇浅讲了「监控 / 日志 / CICD / SRE 实践」(33 / 34 / 40 / 59),networkLearning 给了「反代 / 排障方法论」,osLearning 给了「性能工具 / eBPF」——<strong>这个系列把这些散点接成一张完整的&quot;上线之后&quot;地图</strong>:让系统能跑、能看见、能修、能复盘。 <strong>看完这层,你不再只是&quot;把代码合到 main 上&quot;的工程师</strong>,而是能定 SLO、能写 Runbook、能扛 On-call、能在凌晨三点指挥事故响应的「<strong>对生产系统负责的人</strong>」。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>六层结构,从「文化与心智」到「真刀真枪的生产实战」:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DevOps / SRE 心智(开发 vs 运维 vs SRE / Toil / 错误预算)</span></span>
<span class="line"><span>   → 可观测性三件套(Metrics / Logs / Traces / Profiles)</span></span>
<span class="line"><span>   → SLO 与告警工程(SLI 选择 / 告警分级 / 降噪)</span></span>
<span class="line"><span>   → CI/CD 与发布工程(GitOps / 渐进发布 / Feature Flag)</span></span>
<span class="line"><span>   → IaC 与配置管理(Terraform / Ansible / 配置漂移)</span></span>
<span class="line"><span>   → 生产实战(On-call / 混沌 / 容量 / 复盘 / FinOps)</span></span></code></pre></div><p><strong>这个系列不是 Google SRE Book 翻译</strong>——SRE Book 偏理念,<strong>本系列偏&quot;中型团队工程师视角&quot;</strong>:每篇都对应&quot;你这周可能就要做的一件事&quot;——配 Prometheus 抓 JVM、写一份 Runbook、给灰度发布加门禁、扛一次半夜告警、主持一次复盘。</p><p>不深入到「Google 全球流量调度」「字节级硬件运维」这种极端规模,<strong>而是讲清楚&quot;100-10000 QPS 的真实业务系统怎么稳&quot;</strong>——你写 Java / Go / Node,但代码合上去之后还有一半工作量没做。<strong>这个系列就是那&quot;另一半&quot;。</strong></p><p><strong>写作主线</strong>:每一篇都回答同一个问题——「这件事不做会怎样,做了能多扛多少事故」。不讲&quot;业界最佳实践&quot;这种空话,只讲&quot;我们团队现在 10 个人 / 100 个微服务 / 5000 QPS,这件事该不该做、做到什么程度&quot;。</p><p><strong>一条贯穿全系列的暗线</strong>:三个数字——「<strong>MTTR(故障恢复时间) / MTBF(故障间隔时间) / Change Failure Rate(发布失败率)</strong>」。第二层让 MTTR 降下来,第三层让告警足够早地预警 MTBF 在变短,第四层让 Change Failure Rate 可控,第六层用复盘把这三个数字闭环。读者每读完一层都该回头看一眼:<strong>我把这三个数字往哪个方向推了</strong>?</p><hr><h2 id="篇目-34-篇" tabindex="-1">篇目(34 篇) <a class="header-anchor" href="#篇目-34-篇" aria-label="Permalink to &quot;篇目(34 篇)&quot;">​</a></h2><h3 id="第一层-devops-sre-心智-01-04" tabindex="-1">第一层:DevOps / SRE 心智(01-04) <a class="header-anchor" href="#第一层-devops-sre-心智-01-04" aria-label="Permalink to &quot;第一层:DevOps / SRE 心智(01-04)&quot;">​</a></h3><ul><li>[x] 01 DevOps / SRE 总览(开发 vs 运维 vs SRE / 这个系列要解决什么)</li><li>[x] 02 Google SRE 精华(错误预算 / Toil / 50% 工程时间 / 黄金信号)</li><li>[x] 03 可观测性是什么(监控 ≠ 可观测性 / 三件套 + Profile / Cardinality 陷阱)</li><li>[x] 04 生产系统的&quot;四个真相&quot;(没有 100% 可用 / 失败是常态 / 自动化 / 复盘文化)</li></ul><h3 id="第二层-可观测性三件套-05-12" tabindex="-1">第二层:可观测性三件套(05-12) <a class="header-anchor" href="#第二层-可观测性三件套-05-12" aria-label="Permalink to &quot;第二层:可观测性三件套(05-12)&quot;">​</a></h3><ul><li>[x] 05 Metrics 心智(Counter / Gauge / Histogram / 为什么不要直接存 avg)</li><li>[x] 06 Prometheus 深入(Pull 模型 / 服务发现 / Recording Rule / Federation)</li><li>[x] 07 PromQL 实战(rate / histogram_quantile / 常见踩坑 / 别再用 increase 算 QPS)</li><li>[x] 08 VictoriaMetrics / Thanos / Mimir(Prometheus 长存储与多机房三选一)</li><li>[x] 09 日志系统选型(ELK vs Loki vs ClickHouse / 结构化日志 / 采样)</li><li>[x] 10 日志采集与管道(Vector / Fluent Bit / Filebeat / 边采集边解析)</li><li>[x] 11 OpenTelemetry 与链路追踪(Trace / Span / 上下文传播 / Tempo / Jaeger)</li><li>[x] 12 持续性能剖析(Continuous Profiling / Pyroscope / Parca / eBPF 视角)</li></ul><h3 id="第三层-slo-与告警工程-13-17" tabindex="-1">第三层:SLO 与告警工程(13-17) <a class="header-anchor" href="#第三层-slo-与告警工程-13-17" aria-label="Permalink to &quot;第三层:SLO 与告警工程(13-17)&quot;">​</a></h3><ul><li>[x] 13 SLI / SLO / SLA(怎么定指标 / 用户视角的 SLI / 错误预算的算术)</li><li>[x] 14 RED 与 USE 方法(服务该看什么 / 资源该看什么 / 两者不能混)</li><li>[x] 15 告警分级与降噪(P0 / P1 / P2 / 多窗口多燃烧率 / 别再用静态阈值)</li><li>[x] 16 仪表盘工程(Grafana / 黄金 4 信号 / 一图一意 / 反对&quot;导航灯堆&quot;)</li><li>[x] 17 错误预算的政治学(超支了怎么办 / 谁来踩刹车 / 跟产品怎么吵)</li></ul><h3 id="第四层-ci-cd-与发布工程-18-23" tabindex="-1">第四层:CI/CD 与发布工程(18-23) <a class="header-anchor" href="#第四层-ci-cd-与发布工程-18-23" aria-label="Permalink to &quot;第四层:CI/CD 与发布工程(18-23)&quot;">​</a></h3><ul><li>[x] 18 CI/CD 心智(为什么 CI 必须快 / 流水线分层 / 制品 vs 部署)</li><li>[x] 19 制品仓库与镜像供应链(Harbor / 镜像签名 / SBOM / Cosign)</li><li>[x] 20 GitOps 与 ArgoCD(声明式发布 / Pull vs Push / 多环境 promote)</li><li>[x] 21 渐进发布(蓝绿 / 金丝雀 / 影子流量 / 自动 rollback)</li><li>[x] 22 Feature Flag 工程(LaunchDarkly / Unleash / 灰度维度 / 技术债)</li><li>[x] 23 数据库变更与发布耦合(在线 DDL / Expand-Contract / gh-ost / 蓝绿 schema)</li></ul><h3 id="第五层-iac-与配置管理-24-27" tabindex="-1">第五层:IaC 与配置管理(24-27) <a class="header-anchor" href="#第五层-iac-与配置管理-24-27" aria-label="Permalink to &quot;第五层:IaC 与配置管理(24-27)&quot;">​</a></h3><ul><li>[x] 24 IaC 心智(声明式 vs 命令式 / 不可变基础设施 / 状态文件的诅咒)</li><li>[x] 25 Terraform 深入(state 后端 / module 设计 / drift / import / Terragrunt)</li><li>[x] 26 Pulumi / CDK / Crossplane(用真正的代码写基础设施 / K8s 原生 IaC)</li><li>[x] 27 配置管理(Ansible / 配置中心 / Secret 管理 / Vault / SOPS)</li></ul><h3 id="第六层-生产实战-28-34" tabindex="-1">第六层:生产实战(28-34) <a class="header-anchor" href="#第六层-生产实战-28-34" aria-label="Permalink to &quot;第六层:生产实战(28-34)&quot;">​</a></h3><ul><li>[x] 28 On-call 工程(轮值制度 / Pager / 第一响应 / 不要 hero 文化)</li><li>[x] 29 Runbook 与告警自愈(一个告警一份手册 / 自动化执行步 / 何时升级)</li><li>[x] 30 容量规划(压测 → 模型 → 预算 / 单实例上限 / 弹性容量)</li><li>[x] 31 混沌工程(ChaosMesh / Litmus / 稳态假设 / 从演练到 GameDay)</li><li>[x] 32 事故响应(IC / Comms / Ops 角色 / 战时频道 / 时间线记录)</li><li>[x] 33 Blameless Postmortem(无指责复盘 / 5 Whys / 行动项跟踪 / 文化建设)</li><li>[x] 34 FinOps 与平台工程(成本可观测性 / 平台团队 / DevEx / 这个系列的终点)</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>Docker / K8s 部署</td><td>backendLearning/24-30 ✅</td><td>不重复,只在 IaC / GitOps 里讲 K8s 上的发布</td></tr><tr><td>微服务 / 服务网格</td><td>backendLearning/32 / 60 ✅</td><td>不重复,只讲服务网格出的指标怎么读</td></tr><tr><td>监控基础 / 日志基础</td><td>backendLearning/33-34 ✅</td><td>升级,讲选型 / PromQL / OTel / 长存储</td></tr><tr><td>CICD 基础</td><td>backendLearning/40 ✅</td><td>升级,讲 GitOps / 渐进发布 / 制品安全</td></tr><tr><td>SRE 入门</td><td>backendLearning/59 ✅</td><td>升级,讲 SLO 算术 / On-call / 复盘工程</td></tr><tr><td>IaC 基础</td><td>backendLearning/58 ✅</td><td>升级,讲 state / drift / module 设计</td></tr><tr><td>限流熔断 / 任务调度</td><td>backendLearning/43-44 ✅</td><td>不重复,只在容量规划一篇引用</td></tr><tr><td>压测</td><td>backendLearning/36 ✅</td><td>不重复,本系列把压测结果接到容量模型</td></tr><tr><td>反向代理 / WAF / 排障</td><td>networkLearning/反代+排障 ✅</td><td>不重复,只在链路追踪一篇引用</td></tr><tr><td>性能工具 / eBPF</td><td>osLearning/26-27 ✅</td><td>不重复,只讲&quot;持续性能剖析&quot;工程化</td></tr><tr><td>抗压 / 容灾 / 多机房 / 灰度</td><td>systemDesign ✅</td><td>不重复,只讲容量规划落地与混沌演练</td></tr><tr><td>安全监控 / 应急响应(安全侧)</td><td>securityLearning/29 ✅</td><td>互补,本系列讲可用性视角的事故响应</td></tr><tr><td>供应链安全</td><td>securityLearning/26 ✅</td><td>不重复,只在镜像签名一篇引用</td></tr><tr><td>AI Infra / LLM Ops</td><td>aiLearning ✅</td><td>不重复,只在 FinOps 提 GPU 成本</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇遵守&quot;问题场景 → 工具是什么 → 怎么落地 → 何时不该用&quot;的四段式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 问题场景</span></span>
<span class="line"><span>   - 没这套东西时,生产出过什么事故</span></span>
<span class="line"><span>   - 团队规模到多大、流量到多少会撞上</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 工具 / 方法是什么</span></span>
<span class="line"><span>   - 核心概念 + 一张架构图</span></span>
<span class="line"><span>   - 别家的同类方案怎么比</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 怎么落地</span></span>
<span class="line"><span>   - 一段最小可用的配置 / 代码</span></span>
<span class="line"><span>   - 接入到现有 K8s / 微服务的关键步骤</span></span>
<span class="line"><span>   - 避坑清单(5-10 条踩过的坑)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 何时不该用 / 边界</span></span>
<span class="line"><span>   - 小团队 / 低流量场景该不该上</span></span>
<span class="line"><span>   - 长期维护成本是什么</span></span>
<span class="line"><span>   - 不要把&quot;工具&quot;当成&quot;文化&quot;的替代品</span></span></code></pre></div><p>不堆 yaml,<strong>只贴关键的 20-50 行配置片段</strong>,让读者「看完就能照着改自己的环境」就够了。</p><p><strong>举一个反例</strong>:如果一篇文章打开是 200 行 <code>prometheus.yaml</code>、然后一句&quot;按需修改&quot;,这就是写错了。读者要的是「这条 <code>relabel_configs</code> 为什么必须加」「这个 <code>scrape_interval</code> 设 30s 而不是 15s 的取舍」「为什么我们最终把 <code>alerting.alertmanagers</code> 单独抽出来」——是<strong>取舍的理由</strong>,不是配置的字面值。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-04  心智:看完知道&quot;SRE 不是高级运维,是用工程方法做可靠性&quot;</span></span>
<span class="line"><span>05-12  可观测性:**最值钱的一层**,90% 的事故先在这里被发现</span></span>
<span class="line"><span>13-17  SLO:**最反直觉**,讲完你才知道告警为什么一直在吵 / 一直在漏</span></span>
<span class="line"><span>18-23  CICD:**最贴日常**,每周都在用,但 80% 团队的发布流程都不及格</span></span>
<span class="line"><span>24-27  IaC:**最容易半途而废**,讲清楚状态文件 / drift 才能真上手</span></span>
<span class="line"><span>28-34  生产实战:**面试和真实工作的硬通货**,On-call / 复盘 / 容量 / FinOps</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 05-12 + 13-17 + 28-34 这 20 篇,你应该能在白板前讲清楚:</p><ul><li>&quot;为什么你 dashboard 上的 p99 是骗人的,histogram_quantile 该怎么算&quot;</li><li>&quot;为什么 99.9% 一个月只有 43 分钟错误预算,这 43 分钟该花在哪&quot;</li><li>&quot;为什么告警按静态阈值配一定会爆炸,多窗口多燃烧率是怎么救命的&quot;</li><li>&quot;凌晨三点收到 P0,前 5 分钟你做什么、前 30 分钟你做什么&quot;</li><li>&quot;事故复盘上有人说&#39;这是 XX 的锅&#39;,你怎么把这场会救回来&quot;</li><li>&quot;团队只有 5 个人,该不该上 ArgoCD / Terraform / ChaosMesh,边界在哪&quot;</li><li>&quot;成本同比涨了 40%,FinOps 该从哪个指标先看&quot;</li></ul><p>能讲清楚一题这个系列就值了。</p><p><strong>第二个硬指标</strong>:看完整套之后,你应该能独立写出团队的:</p><ul><li>一份 SLO 文档(SLI 选择 + 错误预算 + 政策)</li><li>一份事故响应手册(角色 + 升级路径 + 沟通模板)</li><li>一份发布门禁清单(CI 必须过的检查 + 发布灰度策略)</li><li>一份 On-call 手册(轮值 + 告警分级 + 升级规则)</li></ul><p>这四份文档不是模板填空——是你<strong>对自己团队的工程承诺</strong>。</p><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li>「装 Prometheus 三步走」——不是工具教程,是工程视角</li><li>「先讲个 Google 全球故障故事」——直接进重点</li><li>罗列 yaml 配置——只贴关键 20-50 行,完整配置丢仓库</li><li>「DevOps 是一种文化」式的口号——文化也要能落到流程和工具上</li><li>抄 Google SRE Book / 《SRE 工作手册》——那两本书在那儿,这里只补它们对中型团队没讲透的工程细节</li><li>不画图就讲 GitOps / 链路追踪 / 错误预算燃烧率——这些<strong>不画图永远讲不清楚</strong></li><li>「上 K8s 就解决一切」——K8s 只是底座,可观测性 / SLO / 发布 / On-call 一样都不能少</li><li>鼓吹&quot;全自动化&quot;——Toil 要减,但盲目自动化只会造出新的 Toil</li><li>「这是面试题」——读者来这里是为了真懂,不是背关键词</li><li>把工具厂商的市场材料当结论——Datadog / New Relic 的白皮书是广告,不是工程经验</li><li>一刀切建议——任何&quot;必须 / 一定 / 永远不要&quot;,都要给出适用条件</li><li>不画 ASCII 图就讲发布流程 / 告警链路 / 事故响应角色——这些<strong>不画图永远讲不清楚</strong>(再说一遍)</li></ol><hr><h2 id="立场声明" tabindex="-1">立场声明 <a class="header-anchor" href="#立场声明" aria-label="Permalink to &quot;立场声明&quot;">​</a></h2><p>本系列<strong>只服务于&quot;对生产系统负责&quot;的工程师视角</strong>——SRE 不是替开发背锅的运维,而是用软件工程方法把可靠性做成可度量、可管理、可改进的产品属性。</p><p>所有示例配置以 <strong>K8s + Prometheus + Loki + OTel + ArgoCD + Terraform</strong> 这套主流栈为默认假设,但每一篇都会标注:换成 VM 部署 / 别的监控栈 / 别的发布工具时,哪些结论依然成立、哪些需要调整。<strong>工具会换,方法不会。</strong></p><p>最后:这个系列<strong>不替代</strong>你团队的真实事故、真实告警、真实压测。它只是给你一张地图,告诉你哪里有坑、哪里别人已经踩过。<strong>真正的工程能力,只能在生产系统上长出来。</strong></p><p>读完整个系列之后,你应该有一种新的本能:看到任何一个新服务上线,会下意识地问——「它的 SLI 是什么 / 错误预算给多少 / 告警怎么配 / 灰度怎么发 / 出事谁 On-call / 复盘什么时候开」。<strong>这套问题就是这个系列要教会你的。</strong></p>`,52)])])}const g=t(e,[["render",i]]);export{h as __pageData,g as default};
